def test_succeed_after_failures():
    sleeps = []
    counter = {'n': 0}
    def flaky():
        counter['n'] += 1
        if counter['n'] < 3:
            raise ValueError('not yet')
        return 'ok'
    p = RetryPolicy(5, ConstantBackoff(0.1), sleep_fn=sleeps.append)
    result = p.execute(flaky)
    assert result == 'ok'
    assert len(sleeps) == 2

def test_exhausted():
    sleeps = []
    def always_fails():
        raise RuntimeError('nope')
    p = RetryPolicy(3, ConstantBackoff(0.1), sleep_fn=sleeps.append)
    try:
        p.execute(always_fails)
        assert False
    except RetryExhausted as e:
        assert len(e.attempts) == 3

def test_retry_only_specific_exceptions():
    p = RetryPolicy(3, ConstantBackoff(0.1), retry_on=(ValueError,), sleep_fn=lambda d: None)
    def bad():
        raise TypeError('not retried')
    try:
        p.execute(bad)
        assert False
    except TypeError:
        pass

def test_attempts_recorded():
    p = RetryPolicy(3, ConstantBackoff(0.1), sleep_fn=lambda d: None)
    counter = {'n': 0}
    def flaky():
        counter['n'] += 1
        if counter['n'] < 2:
            raise ValueError()
        return 'done'
    p.execute(flaky)
    assert len(p.attempts) == 2
    assert p.attempts[0].exception is not None
    assert p.attempts[1].exception is None
